var topic = $.input.researchTopic || '';
var query = topic;
return { query: query, maxResults: $.input.maxSources || 5 };

var results = $.steps.exaSearch.response.results || [];
var sources = results.slice(0, 8).map(function(r, i) {
  return {
    index: i + 1,
    title: r.title || '',
    url: r.url || '',
    text: (r.text || '').slice(0, 2000),
    publishedDate: r.publishedDate || '',
    author: r.author || ''
  };
});
var urls = sources.map(function(s) { return s.url; }).filter(function(u) { return u.length > 0; });
var sourceText = '';
sources.forEach(function(s) {
  sourceText += '=== SOURCE ' + s.index + ' ===\n';
  sourceText += 'Title: ' + s.title + '\n';
  sourceText += 'URL: ' + s.url + '\n';
  sourceText += 'Date: ' + s.publishedDate + '\n';
  sourceText += 'Content:\n' + s.text + '\n\n';
});
return { sources: sources, urls: urls, sourceText: sourceText, sourceCount: sources.length };

var exaSources = $.steps.extractResults.output.sourceText;
var urls = $.steps.extractResults.output.urls;
var iterations = $.steps.scrapeTopResults.response.iterations || [];
var deepContent = '';
iterations.forEach(function(iter, i) {
  var resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;
  if (resp && resp.markdown) {
    deepContent += '=== DEEP SCRAPE ' + (i + 1) + ' ===\n';
    deepContent += 'URL: ' + (urls[i] || '') + '\n';
    deepContent += resp.markdown.slice(0, 3000) + '\n\n';
  }
});
var allContent = exaSources + '\n\n--- ADDITIONAL SCRAPED CONTENT ---\n\n' + deepContent;
return { allContent: allContent.slice(0, 15000), sourceCount: $.steps.extractResults.output.sourceCount };

var data = $.steps.compileResearch.output;
var prompt = 'You are a senior research analyst. Synthesize the following web sources into a comprehensive research report.

';
prompt += 'RESEARCH TOPIC: ' + $.input.researchTopic + '
';
prompt += 'SOURCES ANALYZED: ' + data.sourceCount + '

';
prompt += 'SOURCE MATERIAL:
' + data.allContent + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Write a structured research report with executive summary, key findings, analysis, and conclusions
';
prompt += '- Cite sources where applicable
';
prompt += '- Identify consensus views and contrarian perspectives
';
prompt += '- Rate confidence level for each finding
';
prompt += '- Suggest areas for further research

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "title": "Research report title",
';
prompt += '  "executiveSummary": "2-3 sentence overview",
';
prompt += '  "keyFindings": [{ "finding": "...", "confidence": "High|Medium|Low", "sources": ["url1"] }],
';
prompt += '  "analysis": "Detailed analysis paragraph",
';
prompt += '  "conclusions": ["conclusion1", "conclusion2"],
';
prompt += '  "furtherResearch": ["area1", "area2"],
';
prompt += '  "sourcesUsed": [{ "title": "...", "url": "..." }]
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiResearch.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Research Report', executiveSummary: raw.slice(0, 500), keyFindings: [], analysis: raw, conclusions: [], furtherResearch: [], sourcesUsed: [] }; }

var ai = $.steps.parseAI.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: (ai.title || 'Research Report').slice(0, 150), emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Executive Summary:*\n' + (ai.executiveSummary || '').slice(0, 1800) } });
blocks.push({ type: 'divider' });
var findings = ai.keyFindings || [];
if (findings.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Key Findings:*' } });
  findings.slice(0, 6).forEach(function(f, i) {
    var text = (i + 1) + '. ' + f.finding;
    if (f.confidence) text += ' _(' + f.confidence + ' confidence)_';
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
  });
}
blocks.push({ type: 'divider' });
if (ai.analysis) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Analysis:*\n' + ai.analysis.slice(0, 2500) } });
}
if (ai.conclusions && ai.conclusions.length > 0) {
  blocks.push({ type: 'divider' });
  var concText = '*Conclusions:*\n';
  ai.conclusions.forEach(function(c, i) { concText += (i + 1) + '. ' + c + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: concText.slice(0, 1800) } });
}
if (ai.sourcesUsed && ai.sourcesUsed.length > 0) {
  var srcText = '*Sources:*\n';
  ai.sourcesUsed.slice(0, 8).forEach(function(s) {
    srcText += '- <' + s.url + '|' + s.title + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Researched with Exa + Firecrawl + Claude AI via One CLI' }] });
var fallback = (ai.title || 'Research') + ': ' + (ai.executiveSummary || '').slice(0, 200);
return { blocks: blocks, fallback: fallback };
